 * @param targetName Name for the target node
 * @return bool Whether observer reset worked correctly (observer no longer notified after reset)
 */
bool test_observer_reset(const std::string& observerName, const std::string& targetName) {
    // Step 1: Create observer nodes
    auto target = std::make_shared<TestObserverReset>(targetName);
    auto observer = std::make_shared<TestObserverReset>(observerName);

    // Step 2: Get observer graph instance
    auto& graph = reaction::ObserverGraph::getInstance();

    // Step 3: Add observer relationship
    target->addOneObserver(observer);

    // Step 4: Notify target and verify observer was notified
    target->valueChanged(true);

    // Verify observer was notified
    if (observer->getCallCount() != 1 || !observer->wasChanged()) {
        return false; // Observer was not properly notified
    }

    // Step 5: Record call count before reset
    int callCountBeforeReset = observer->getCallCount();

    // Step 6: Reset observer node
    observer->reset();

    // Step 7: Notify target again
    target->valueChanged(true);

    // Step 8: Verify observer was not notified after reset
    // The observer should not have been notified again since it was reset
    // and the reset should have cleared its state
    if (observer->getCallCount() != 0 || observer->wasChanged()) {
        return false; // Observer was notified after reset
    }

    // Step 9: Return success status
    return true;
}

}  // namespace test_reaction
