 *
 * @param a First input value
 * @param b Second input value
 * @param newA New value for a
 * @return int The result of the final calculation after updating a
 */
int test_reactive_update_chain(int a, int b, int newA) {
    // 1. Create reactive variables
    auto varA = reaction::Var<int>(a);
    auto varB = reaction::Var<int>(b);

    // 2. Create first calculation (depends on variables)
    auto calc1 = reaction::Expr<int>([&varA, &varB]() {
        return varA.get() + varB.get();
    });

    // 3. Create second calculation (depends on first calculation)
    auto calc2 = reaction::Expr<int>([&calc1]() {
        return calc1.get() * 2;
    });

    // 4. Update variable
    varA = newA;

    // 5. Return final calculation result
    return calc2.get();
}

