    auto node1 = std::make_shared<CacheProbeNode>();
    auto node2 = std::make_shared<CacheProbeNode>();
    auto node3 = std::make_shared<CacheProbeNode>();
    auto node4 = std::make_shared<CacheProbeNode>();

    // Step 2: Get observer graph instance
    auto& graph = reaction::ObserverGraph::getInstance();

    // Step 3: Register nodes (nodes are automatically registered when observers are added)

    // Step 4: Set up direct observer relationship
    // node1 observes node2
    graph.addObserver(node2, node1);

    // Step 5: Set up transitive observer relationship
    // node2 observes node3, node3 observes node4
    // This creates: node1 -> node2 -> node3 -> node4
    graph.addObserver(node3, node2);
    graph.addObserver(node4, node3);

    // Step 6: Create NodeSet to store collected observers
    reaction::NodeSet observers;

    // Step 7: Populate cache data by collecting observers
    // This will populate the cache with traversal results
    graph.collectObservers(node4, observers);

    // Collect again to potentially hit the cache
    reaction::NodeSet observers2;
    graph.collectObservers(node4, observers2);

    // Step 8: Get cache statistics before cleanup
    auto statsBefore = graph.getCacheStats();
    size_t graphEntriesBeforeCleanup = statsBefore.currentEntries;

    // Step 9: Trigger cache cleanup
    graph.triggerCacheCleanup();

    // Step 10: Get cache statistics after cleanup
    auto statsAfter = graph.getCacheStats();
    size_t graphEntriesAfterCleanup = statsAfter.currentEntries;
    double graphHitRatioAfterCleanup = statsAfter.hitRatio;

    // Step 11: Close all nodes by removing observers
    // This ensures proper cleanup
    graph.removeObserver(node2, node1);
    graph.removeObserver(node3, node2);
    graph.removeObserver(node4, node3);

    // Step 12: Return cache stats snapshot
    return CacheStatsSnapshot{
        graphEntriesBeforeCleanup,
        graphEntriesAfterCleanup,
        graphHitRatioAfterCleanup
    };
}

}  // namespace test_reaction

