namespace test_reaction {

// Simple conditional mutex wrapper that uses thread manager state
class ConditionalMutex {
private:
    std::mutex mutex_;

public:
    class ConditionalLockGuard {
    private:
        std::unique_lock<std::mutex> lock_;
        bool safetyEnabled_;

    public:
        ConditionalLockGuard(ConditionalMutex& mutex) 
            : safetyEnabled_(reaction::ThreadManager::getInstance().isThreadSafetyEnabled()) {
            if (safetyEnabled_) {
                lock_ = std::unique_lock<std::mutex>(mutex.mutex_);
            }
        }

        bool isLocked() const { return safetyEnabled_ && lock_.owns_lock(); }
    };

    bool try_lock() {
        auto& tm = reaction::ThreadManager::getInstance();
        if (tm.isThreadSafetyEnabled()) {
            return mutex_.try_lock();
        }
        return true; // Always "succeed" when safety is disabled
    }

    void unlock() {
        auto& tm = reaction::ThreadManager::getInstance();
        if (tm.isThreadSafetyEnabled()) {
            mutex_.unlock();
        }
    }
};

ConditionalMutexResult test_conditional_mutex_behavior() {
