    threadManager.enableThreadSafety();

    // 8. Create ConditionalLockGuard in a scope block again (with safety)
    {
        ConditionalMutex::ConditionalLockGuard guard(mutex);
        // 9. Attempt to lock mutex with safety enabled
        result.tryLockWithSafety = mutex.try_lock();
    }
